import React, { useEffect, useState } from "react";
import API from "../../api/api";

const fmt = (d) => d ? new Date(d).toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"}) : "";

export default function Earnings() {
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get("/proposals/my").then(r=>{setProposals(r.data||[]);setLoading(false);}).catch(()=>setLoading(false));
  }, []);

  const accepted = proposals.filter(p=>p.status==="accepted");
  const pending  = proposals.filter(p=>!p.status||p.status==="pending");
  const rejected = proposals.filter(p=>p.status==="rejected");
  const acceptedVal = accepted.reduce((s,p)=>s+parseFloat(p.bid||0),0);
  const pendingVal  = pending.reduce((s,p)=>s+parseFloat(p.bid||0),0);

  const S = {
    page: { background:"#0f172a", minHeight:"100vh", padding:"32px", fontFamily:"'Segoe UI',sans-serif" },
    title: { fontSize:"24px", fontWeight:"700", color:"#f1f5f9", marginBottom:"4px" },
    sub: { fontSize:"13px", color:"#64748b", marginBottom:"28px" },
    grid4: { display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:"16px", marginBottom:"24px" },
    card: (accent) => ({ background:"#1e293b", border:`1px solid #334155`, borderTop:`3px solid ${accent}`, borderRadius:"14px", padding:"20px" }),
    lbl: { fontSize:"10px", fontWeight:"700", color:"#64748b", textTransform:"uppercase", letterSpacing:"1px", marginBottom:"6px" },
    val: (c) => ({ fontSize:"24px", fontWeight:"800", color:c }),
    hint: { fontSize:"11px", color:"#475569", marginTop:"4px" },
    grid3: { display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:"14px", marginBottom:"24px" },
    statCard: (bg,border,color) => ({ background:bg, border:`1px solid ${border}`, borderRadius:"12px", padding:"20px", textAlign:"center" }),
    statNum: (c) => ({ fontSize:"32px", fontWeight:"800", color:c, margin:"0 0 4px" }),
    statLbl: (c) => ({ fontSize:"12px", fontWeight:"600", color:c }),
    table: { background:"#1e293b", border:"1px solid #334155", borderRadius:"14px", overflow:"hidden" },
    thead: { display:"grid", gridTemplateColumns:"2fr 1fr 1fr 1fr 1fr", background:"#0f172a", padding:"12px 20px", gap:"10px", borderBottom:"1px solid #334155" },
    th: { fontSize:"10px", fontWeight:"700", color:"#64748b", textTransform:"uppercase", letterSpacing:"0.8px" },
    trow: { display:"grid", gridTemplateColumns:"2fr 1fr 1fr 1fr 1fr", padding:"14px 20px", gap:"10px", borderBottom:"1px solid #1e293b", alignItems:"center" },
    td: { fontSize:"13px", color:"#94a3b8" },
    badge: (s) => {
      const m = {accepted:["rgba(74,222,128,0.1)","rgba(74,222,128,0.3)","#4ade80"],rejected:["rgba(248,113,113,0.1)","rgba(248,113,113,0.3)","#f87171"],pending:["rgba(251,191,36,0.1)","rgba(251,191,36,0.3)","#fbbf24"]};
      const [bg,b,c] = m[s]||m.pending;
      return { background:bg, border:`1px solid ${b}`, color:c, fontSize:"10px", fontWeight:"700", padding:"3px 10px", borderRadius:"20px", textTransform:"capitalize", display:"inline-block" };
    },
  };

  if (loading) return <div style={{...S.page,display:"flex",alignItems:"center",justifyContent:"center"}}><span style={{color:"#2dd4bf"}}>Loading...</span></div>;

  return (
    <div style={S.page}>
      <h1 style={S.title}>Earnings Dashboard</h1>
      <p style={S.sub}>Track your bids and proposal income</p>

      <div style={S.grid4}>
        {[
          { label:"Total Earned", value:"₹0", color:"#4ade80", accent:"#4ade80", hint:"No withdrawals yet" },
          { label:"Accepted Value", value: acceptedVal>0?`₹${acceptedVal.toLocaleString()}`:"₹0", color:"#38bdf8", accent:"#38bdf8", hint:"From accepted bids" },
          { label:"Pending Value", value: pendingVal>0?`₹${pendingVal.toLocaleString()}`:"₹0", color:"#fbbf24", accent:"#fbbf24", hint:"Awaiting decision" },
          { label:"Total Proposals", value: proposals.length, color:"#a78bfa", accent:"#a78bfa", hint:"All time" },
        ].map((c,i)=>(
          <div key={i} style={S.card(c.accent)}>
            <p style={S.lbl}>{c.label}</p>
            <p style={S.val(c.color)}>{c.value}</p>
            <p style={S.hint}>{c.hint}</p>
          </div>
        ))}
      </div>

      <div style={S.grid3}>
        <div style={S.statCard("rgba(74,222,128,0.06)","rgba(74,222,128,0.2)","#4ade80")}>
          <p style={S.statNum("#4ade80")}>{accepted.length}</p>
          <p style={S.statLbl("#4ade80")}>✅ Accepted</p>
        </div>
        <div style={S.statCard("rgba(251,191,36,0.06)","rgba(251,191,36,0.2)","#fbbf24")}>
          <p style={S.statNum("#fbbf24")}>{pending.length}</p>
          <p style={S.statLbl("#fbbf24")}>⏳ Pending</p>
        </div>
        <div style={S.statCard("rgba(248,113,113,0.06)","rgba(248,113,113,0.2)","#f87171")}>
          <p style={S.statNum("#f87171")}>{rejected.length}</p>
          <p style={S.statLbl("#f87171")}>❌ Rejected</p>
        </div>
      </div>

      <div style={S.table}>
        <div style={{ padding:"16px 20px", borderBottom:"1px solid #334155" }}>
          <span style={{ fontSize:"14px", fontWeight:"700", color:"#f1f5f9" }}>All Proposals & Earnings</span>
        </div>
        <div style={S.thead}>
          {["Project","Your Bid","Budget","Date","Status"].map(h=><span key={h} style={S.th}>{h}</span>)}
        </div>
        {proposals.length===0 ? (
          <div style={{textAlign:"center",padding:"40px",color:"#475569"}}>No proposals yet</div>
        ) : proposals.map(p=>(
          <div key={p.id} style={S.trow}>
            <span style={{...S.td,color:"#e2e8f0",fontWeight:"600"}}>{p.project_title}</span>
            <span style={{...S.td,color:"#4ade80",fontWeight:"700"}}>₹{p.bid}</span>
            <span style={S.td}>₹{p.project_budget||"—"}</span>
            <span style={S.td}>{fmt(p.created_at)}</span>
            <span style={S.badge(p.status)}>{p.status||"pending"}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
